{
var input = inputs.Length > 0 ? inputs[0] : null;
        if (input is null)
            return PixelBuffer.CreateSolid(context.TileSize, context.TileSize, 0, 0, 0);

        var seed = GetInt(parameters, "seed", context.Seed);
        var distortType = GetChoice(parameters, "distortType", "noise");
        var strength = GetFloat(parameters, "intensity", 0.05f);
        var frequency = GetFloat(parameters, "frequency", 3f);
        var octaves = GetInt(parameters, "octaves", 2);
        var xStrength = GetFloat(parameters, "xStrength", 1f);
        var yStrength = GetFloat(parameters, "yStrength", 1f);
        var angle = GetFloat(parameters, "angle", 0f) * MathF.PI / 180f;
        var centerX = GetFloat(parameters, "centerX", 0.5f);
        var centerY = GetFloat(parameters, "centerY", 0.5f);

        var size = input.Width;
        var result = new PixelBuffer(size, size);
        var period = Math.Max(1, (int)MathF.Round(frequency));

        result.ParallelForEachPixel((x, y) =>
        {
            var nx = x / (float)size * frequency;
            var ny = y / (float)size * frequency;
            float dx, dy;

            switch (distortType)
            {
                case "swirl":
                {
                    var relX = x / (float)size - centerX;
                    var relY = y / (float)size - centerY;
                    var dist = MathF.Sqrt(relX * relX + relY * relY);
                    var swirlAngle = dist * strength * 40f;
                    var cosA = MathF.Cos(swirlAngle);
                    var sinA = MathF.Sin(swirlAngle);
                    dx = (relX * cosA - relY * sinA - relX) * size;
                    dy = (relX * sinA + relY * cosA - relY) * size;
                    break;
                }
                case "ripple":
                {
                    var relX = x / (float)size - centerX;
                    var relY = y / (float)size - centerY;
                    var dist = MathF.Sqrt(relX * relX + relY * relY);
                    var wave = MathF.Sin(dist * frequency * MathF.Tau + angle) * strength;
                    if (dist > 0.001f)
                    {
                        dx = wave * (relX / dist) * size;
                        dy = wave * (relY / dist) * size;
                    }
                    else
                    {
                        dx = 0; dy = 0;
                    }
                    break;
                }
                case "pinch":
                {
                    var relX = x / (float)size - centerX;
                    var relY = y / (float)size - centerY;
                    var dist = MathF.Sqrt(relX * relX + relY * relY);
                    // Guard against Pow(0, negative) which returns Infinity, producing NaN downstream.
                    var safeDist = MathF.Max(dist, 0.001f);
                    var factor = MathF.Pow(safeDist, 1f + strength * 5f) / safeDist;
                    dx = (relX * factor - relX) * size;
                    dy = (relY * factor - relY) * size;
                    break;
                }
                case "polar":
                {
                    var relX = x / (float)size - centerX;
                    var relY = y / (float)size - centerY;
                    var theta = MathF.Atan2(relY, relX);
                    var dist = MathF.Sqrt(relX * relX + relY * relY);
                    // Map angle to x, distance to y
                    var polarX = (theta / MathF.Tau + 0.5f) * size;
                    var polarY = dist * 2f * size;
                    dx = (polarX - x) * strength * 2f;
                    dy = (polarY - y) * strength * 2f;
                    break;
                }
                default: // "noise"
                {
                    var noiseX = TileableFractalNoise(nx, ny, period, octaves, 0.5f, 2f, seed) - 0.5f;
                    var noiseY = TileableFractalNoise(nx, ny, period, octaves, 0.5f, 2f, seed + 777) - 0.5f;

                    // Apply directional angle
                    if (MathF.Abs(angle) > 0.001f)
                    {
                        var cosD = MathF.Cos(angle);
                        var sinD = MathF.Sin(angle);
                        var rotX = noiseX * cosD - noiseY * sinD;
                        var rotY = noiseX * sinD + noiseY * cosD;
                        noiseX = rotX;
                        noiseY = rotY;
                    }

                    dx = noiseX * strength * size * xStrength;
                    dy = noiseY * strength * size * yStrength;
                    break;
                }
            }

            var sampleX = x + dx;
            var sampleY = y + dy;

            // Wrap for tileability
            var sx = ((int)MathF.Round(sampleX) % size + size) % size;
            var sy = ((int)MathF.Round(sampleY) % size + size) % size;

            var (r, g, b, a) = input.GetPixelWrapped(sx, sy);
            result.SetPixel(x, y, r, g, b, a);
        });

        return result;
}
